import { __decorate } from "tslib";
import { Component, Input } from '@angular/core';
import { moduleMetadata } from '@storybook/angular';
import { PfTableComponent } from './table.component';
import { PfTagComponent } from '../tag/tag.component';
import { PfPaginationComponent } from '../pagination/pagination.component';
const demandes = [
    { id: '1', numero: '2026-0042', demandeur: 'Marie Dupont', type: 'Permis bateau', statut: 'en_cours', date: '2026-04-22' },
    { id: '2', numero: '2026-0041', demandeur: 'Jean Martin', type: 'Renouvellement licence', statut: 'valide', date: '2026-04-21' },
    { id: '3', numero: '2026-0040', demandeur: 'Léa Tehina', type: 'Inscription navire', statut: 'brouillon', date: '2026-04-21' },
    { id: '4', numero: '2026-0039', demandeur: 'Pierre Faatau', type: 'Permis bateau', statut: 'refuse', date: '2026-04-20' },
    { id: '5', numero: '2026-0038', demandeur: 'Sophie Lai', type: 'Permis hauturier', statut: 'valide', date: '2026-04-19' },
];
const STATUT_VARIANT = {
    brouillon: 'neutral',
    en_cours: 'info',
    valide: 'success',
    refuse: 'danger',
};
const STATUT_LABEL = {
    brouillon: 'Brouillon',
    en_cours: 'En cours',
    valide: 'Validé',
    refuse: 'Refusé',
};
let TableDemo = class TableDemo {
    constructor() {
        this.selectable = 'none';
        this.sortable = false;
        this.rows = demandes;
        this.selectedIds = [];
        this.selectedId = '';
        this.selectedRow = null;
        this.sort = null;
        this.rowKey = (r) => r.id;
    }
    get columns() {
        return [
            { key: 'numero', label: 'Numéro', width: '120px', sortable: this.sortable },
            { key: 'demandeur', label: 'Demandeur', sortable: this.sortable },
            { key: 'type', label: 'Type' },
            { key: 'statut', label: 'Statut' },
            { key: 'date', label: 'Date', width: '120px', sortable: this.sortable },
        ];
    }
    variantFor(s) {
        return STATUT_VARIANT[s];
    }
    labelFor(s) {
        return STATUT_LABEL[s];
    }
    onSortChange(s) {
        this.sort = s;
        const av = (a) => String(a[s.column] ?? '');
        this.rows = [...this.rows].sort((a, b) => {
            const cmp = av(a).localeCompare(av(b), 'fr');
            return s.direction === 'asc' ? cmp : -cmp;
        });
    }
    onRowSelect(row) {
        this.selectedRow = row;
        this.selectedId = row.id;
    }
    static { this.propDecorators = {
        selectable: [{ type: Input }],
        sortable: [{ type: Input }],
        rows: [{ type: Input }]
    }; }
};
TableDemo = __decorate([
    Component({
        selector: 'pf-table-demo',
        standalone: true,
        imports: [PfTableComponent, PfTagComponent, PfPaginationComponent],
        template: `
    <pf-table
      caption="Liste des demandes"
      [columns]="columns"
      [rows]="rows"
      [rowKey]="rowKey"
      [selectable]="selectable"
      [selectedRowIds]="selectedIds"
      [selectedRowId]="selectedId"
      [sort]="sort"
      [striped]="striped"
      (sortChange)="onSortChange($event)"
      (selectionChange)="selectedIds = $event"
      (rowSelect)="onRowSelect($event)"
    >
      <ng-template #statutTpl let-row>
        <pf-tag [variant]="variantFor(row.statut)">{{ labelFor(row.statut) }}</pf-tag>
      </ng-template>
    </pf-table>
    @if (selectable === 'multiple') {
      <p style="color: var(--color-text-secondary); margin: 12px 0 0; font-size: 14px;">
        {{ selectedIds.length }} ligne(s) sélectionnée(s)
      </p>
    }
    @if (selectable === 'single' && selectedRow) {
      <p style="color: var(--color-text-secondary); margin: 12px 0 0; font-size: 14px;">
        Sélection : <strong>{{ selectedRow.demandeur }}</strong>
      </p>
    }
  `,
    })
], TableDemo);
const meta = {
    title: 'Composants/Table',
    component: TableDemo,
    tags: ['autodocs'],
    parameters: {
        docs: {
            description: {
                component: "Table data-driven : `[columns]` + `[rows]`. Pagination externe (utiliser `<pf-pagination>`), sort server-driven (`(sortChange)`), sélection via `[selectable]=\"'none' | 'single' | 'multiple'\"`.",
            },
        },
    },
    decorators: [
        moduleMetadata({ imports: [TableDemo] }),
        (storyFn) => {
            const story = storyFn();
            return { ...story, template: `<div style="width: 800px;">${story.template}</div>` };
        },
    ],
};
export default meta;
export const Default = { args: {} };
export const Sortable = { args: { sortable: true } };
export const SingleSelect = { args: { selectable: 'single' } };
export const MultipleSelect = { args: { selectable: 'multiple' } };
